---
import type { HTMLAttributes } from "astro/types";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
}

export const navigationMenuTriggerStyle = cva(
  "navigation-menu-trigger-surface cn-navigation-menu-trigger group/navigation-menu-trigger inline-flex h-9 w-max items-center justify-center rounded-sm bg-transparent px-4 py-2.5 text-sm font-medium transition-[color,box-shadow] outline-none disabled:pointer-events-none disabled:opacity-50 border-none cursor-pointer gap-1.5 relative z-1 hover:bg-muted hover:text-foreground focus:bg-muted focus:text-foreground focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 data-[state=open]:bg-muted data-[state=open]:text-foreground data-open:bg-muted/50 data-open:hover:bg-muted data-open:focus:bg-muted data-popup-open:bg-muted/50 data-popup-open:hover:bg-muted",
);

const {
  class: className = "",
  type = "button",
  ...rest
} = Astro.props as Props;
---

<button
  {...rest}
  data-slot="navigation-menu-trigger"
  type={type}
  class={cn(navigationMenuTriggerStyle(), "group", className)}
>
  <slot />
  <SemanticIcon
    name="chevron-down"
    class="cn-navigation-menu-trigger-icon text-muted-foreground relative top-px ml-1 size-3 transition duration-300 group-data-open/navigation-menu-trigger:rotate-180 group-data-popup-open/navigation-menu-trigger:rotate-180 group-data-[state=open]/navigation-menu-trigger:rotate-180"
    aria-hidden="true"
  />
</button>

---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  align?: "start" | "center" | "end";
  alignOffset?: number;
  side?: "top" | "bottom";
  sideOffset?: number;
}

const {
  class: className = "",
  align = "start",
  alignOffset = 0,
  side = "bottom",
  sideOffset = 4,
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  data-slot="navigation-menu-content"
  data-align={align}
  data-align-offset={alignOffset}
  data-side={side}
  data-side-offset={sideOffset}
  hidden
  class={cn(
    "cn-navigation-menu-content",
    "h-full w-auto absolute transition-[opacity,transform,translate] duration-[0.35s] ease-[cubic-bezier(0.22,1,0.36,1)]",
    "data-starting-style:pointer-events-none data-starting-style:opacity-0 data-ending-style:opacity-0",
    "data-starting-style:data-activation-direction=left:translate-x-[-50%]",
    "data-starting-style:data-activation-direction=right:translate-x-[50%]",
    "data-ending-style:data-activation-direction=left:translate-x-[50%]",
    "data-ending-style:data-activation-direction=right:translate-x-[-50%]",
    "**:data-[slot=navigation-menu-link]:focus:ring-0 **:data-[slot=navigation-menu-link]:focus:outline-none",
    className,
  )}
>
  <slot />
</div>

