---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div
  {...rest}
  data-slot="navigation-menu-indicator"
  class={cn("cn-navigation-menu-indicator",
    "absolute left-0 top-0 z-0 rounded-[calc(var(--radius)-2px)] data-instant:transition-opacity transition-[translate,width,height] duration-150 ease pointer-events-none opacity-0 data-[state=visible]:opacity-100",
    "translate-x-(--indicator-left,0px) translate-y-(--indicator-top,0px)",
    "w-(--indicator-width,0) h-(--indicator-height,0)",
    className,
  )}
>
  <div class="cn-navigation-menu-indicator-surface absolute inset-0 rounded-[inherit] bg-muted/45 ring-1 ring-border/40"></div>
  <div class="cn-navigation-menu-indicator-arrow absolute top-full left-1/2 h-2 w-2 -translate-x-1/2 -translate-y-[40%] rotate-45 rounded-tl-sm bg-border opacity-0 shadow-sm"></div>
</div>

export { default as NavigationMenu } from "./NavigationMenu.astro";
export { default as NavigationMenuList } from "./NavigationMenuList.astro";
export { default as NavigationMenuItem } from "./NavigationMenuItem.astro";
export { default as NavigationMenuTrigger } from "./NavigationMenuTrigger.astro";
export { default as NavigationMenuContent } from "./NavigationMenuContent.astro";
export { default as NavigationMenuPositioner } from "./NavigationMenuPositioner.astro";
export { default as NavigationMenuViewport } from "./NavigationMenuViewport.astro";
export { default as NavigationMenuLink } from "./NavigationMenuLink.astro";
export { default as NavigationMenuIndicator } from "./NavigationMenuIndicator.astro";
export { navigationMenuTriggerStyle } from "./NavigationMenuTrigger.astro";

---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";
import NavigationMenuViewport from "./NavigationMenuViewport.astro";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  popupClass?: string;
  viewportClass?: string;
}

const {
  class: className = "",
  popupClass = "",
  viewportClass = "",
  ...rest
} = Astro.props as Props;
---

<div data-slot="navigation-menu-portal">
  <div
    {...rest}
    data-slot="navigation-menu-positioner"
    class={cn(
      "cn-navigation-menu-positioner isolate z-50 h-(--positioner-height) w-(--positioner-width) max-w-(--available-width) data-instant:transition-none",
      className,
    )}
  >
    <div
      data-slot="navigation-menu-popup"
      class={cn(
        "cn-navigation-menu-popup xs:w-(--popup-width) relative h-(--popup-height) w-(--popup-width) origin-(--transform-origin) outline-none",
        popupClass,
      )}
    >
      <NavigationMenuViewport class={viewportClass} />
    </div>
  </div>
</div>
